// Helper: get questions filtered by subject and grade
export function getQuestions(subject: NafsQuestion['subject'], grade: NafsQuestion['grade'], domain?: string): NafsQuestion[] {
  return nafsQuestions.filter(q =>
    q.subject === subject && q.grade === grade && (domain ? q.domain === domain : true)
  );
}

// Get unique domains for a subject+grade combo
export function getDomains(subject: NafsQuestion['subject'], grade: NafsQuestion['grade']): string[] {
  const all = nafsQuestions.filter(q => q.subject === subject && q.grade === grade);
  return [...new Set(all.map(q => q.domain))];
}